def _load_model():
    model_bytes = base64.b64decode(_EMBEDDED_MODEL_B64)
    return np.load(BytesIO(model_bytes), allow_pickle=False)


class Classifier:
    def __init__(self):
        """
        Load the trained model once when the classifier is instantiated.
        """
        data = _load_model()

        self.mean = data["mean"].astype(np.float64, copy=False)
        self.std = np.where(data["std"] == 0, 1.0, data["std"]).astype(np.float64, copy=False)
        self.classes = data["classes"].astype(np.int64)
        self.activation = str(data["activation"])
        self.num_layers = int(data["num_layers"])
        self.coefs = [data[f"coef_{idx}"].astype(np.float64, copy=False) for idx in range(self.num_layers)]
        self.intercepts = [data[f"intercept_{idx}"].astype(np.float64, copy=False) for idx in range(self.num_layers)]

    def inference(self, X: np.array) -> np.array:
        """
        Inference all input feature vectors.

        Args:
            X: Feature vectors with shape [a, 256].

        Returns:
            Predicted category indices with shape [a].
        """
        X = np.asarray(X, dtype=np.float64)
        if X.ndim == 1:
            X = X.reshape(1, -1)
        if X.shape[1] == self.mean.shape[0] + 1:
            X = X[:, 1:]
        if X.shape[1] != self.mean.shape[0]:
            raise ValueError(f"Expected {self.mean.shape[0]} features, got {X.shape[1]}")

        predictions = []
        chunk_size = 4096
        for start in range(0, X.shape[0], chunk_size):
            hidden = (X[start : start + chunk_size] - self.mean) / self.std
            for coef, intercept in zip(self.coefs[:-1], self.intercepts[:-1]):
                hidden = hidden @ coef + intercept
                if self.activation == "relu":
                    hidden = np.maximum(hidden, 0.0)
                elif self.activation == "tanh":
                    hidden = np.tanh(hidden)
                elif self.activation == "logistic":
                    hidden = 1.0 / (1.0 + np.exp(-hidden))
                else:
                    raise ValueError(f"Unsupported activation: {self.activation}")

            logits = hidden @ self.coefs[-1] + self.intercepts[-1]
            predictions.append(self.classes[np.argmax(logits, axis=1)])

        return np.concatenate(predictions).astype(np.int64)
